def smart_round(value: float) -> float:
    """
    根据数值大小智能调整精度进行四舍五入
    Args:
        value: 需要四舍五入的数值
    Returns:
        根据数值大小调整精度后的四舍五入结果
    规则:
        - abs(value) >= 1000: 保留0位小数
        - abs(value) >= 100: 保留1位小数
        - abs(value) >= 10: 保留2位小数
        - abs(value) >= 1: 保留3位小数
        - abs(value) >= 0.1: 保留4位小数
        - abs(value) >= 0.01: 保留5位小数
        - abs(value) >= 0.001: 保留6位小数
        - abs(value) >= 0.0001: 保留7位小数
        - abs(value) >= 0.00001: 保留8位小数
        - abs(value) >= 0.000001: 保留9位小数
        - abs(value) >= 0.0000001: 保留10位小数
        - abs(value) >= 0.00000001: 保留11位小数
        - 否则: 保留12位小数
    """
    if value == 0:
        return 0.0
    abs_value = abs(value)
    if abs_value >= 1000:
        return round(value, 0)
    elif abs_value >= 100:
        return round(value, 1)
    elif abs_value >= 10:
        return round(value, 2)
    elif abs_value >= 1:
        return round(value, 3)
    elif abs_value >= 0.1:
        return round(value, 4)
    elif abs_value >= 0.01:
        return round(value, 5)
    elif abs_value >= 0.001:
        return round(value, 6)
    elif abs_value >= 0.0001:
        return round(value, 7)
    elif abs_value >= 0.00001:
        return round(value, 8)
    elif abs_value >= 0.000001:
        return round(value, 9)
    elif abs_value >= 0.0000001:
        return round(value, 10)
    elif abs_value >= 0.00000001:
        return round(value, 11)
    else:
        return round(value, 12)
def _map_parameter_keys(converted_params: dict, expected_keys: set) -> dict:
    """
    映射转换后的参数键名到期望的键名
    参数:
        converted_params: 转换后的参数字典
        expected_keys: 期望的参数键集合
    返回:
        映射后的参数字典
    映射规则:
        1. 显式映射规则（优先级最高）
        2. 如果键已经在期望的键中，直接使用
        3. 智能匹配：尝试将 C_xxx 映射到 Cap_xxx
    """
    # 定义显式键名映射规则
    explicit_key_mapping = {
        'C_filter': 'Cap_filter',
        'C_out': 'Cap_out',
        # 可以根据需要添加更多映射规则
    }
    # 创建映射后的参数字典
    mapped_params = {}
    used_expected_keys = set()  # 记录已使用的期望键，避免重复映射
    for key, value in converted_params.items():
        mapped_key = None
        # 1. 检查显式映射规则
        if key in explicit_key_mapping:
            mapped_key = explicit_key_mapping[key]
        # 2. 如果键已经在期望的键中，直接使用
        elif key in expected_keys:
            mapped_key = key
        # 3. 智能匹配：尝试将 C_xxx 映射到 Cap_xxx
        elif key.startswith('C_'):
            potential_key = 'Cap' + key[1:]  # C_filter -> Cap_filter
            if potential_key in expected_keys and potential_key not in used_expected_keys:
                mapped_key = potential_key
        # 如果找到了映射的键，且该键在期望的键中，使用映射后的键
        if mapped_key and mapped_key in expected_keys and mapped_key not in used_expected_keys:
            mapped_params[mapped_key] = value
            used_expected_keys.add(mapped_key)
        else:
            # 无法映射或映射后的键不在期望的键中，保留原键（作为多余的键，允许存在）
            mapped_params[key] = value
    return mapped_params
class LogCollector:
    """
    日志收集器，用于收集所有warning和error信息，保存到结果中
    """
    def **init**(self):
        self.logs: List[Dict[str, Any]] = []
    def add_log(self, level: str, message: str, details: Optional[Dict[str, Any]] = None):
        """
        添加日志
        参数:
            level: 日志级别 (INFO, WARN, ERROR)
            message: 日志消息
            details: 额外的详细信息字典
        """
        log_entry = {
            "timestamp": datetime.now().isoformat(),
            "level": level,
            "message": message,
        }
        if details:
            log_entry["details"] = details
        self.logs.append(log_entry)
    def info(self, message: str, details: Optional[Dict[str, Any]] = None):
        self.add_log("INFO", message, details)
    def warn(self, message: str, details: Optional[Dict[str, Any]] = None):
        self.add_log("WARN", message, details)
    def error(self, message: str, details: Optional[Dict[str, Any]] = None):
        self.add_log("ERROR", message, details)
    def exception(self, message: str, exception: Exception, details: Optional[Dict[str, Any]] = None):
        """
        记录异常信息
        """
        exc_details = {
            "exception_type": type(exception).__name__,
            "exception_message": str(exception),
            "traceback": traceback.format_exc(),
        }
        if details:
            exc_details.update(details)
        self.error(message, exc_details)
    def get_logs(self) -> List[Dict[str, Any]]:
        """获取所有日志"""
        return self.logs.copy()
    def clear(self):
        """清空日志"""
        self.logs.clear()
    def to_dict(self) -> Dict[str, Any]:
        """转换为字典格式，包含统计信息"""
        return {
            "logs": self.logs,
            "total_count": len(self.logs),
            "error_count": sum(1 for log in self.logs if log["level"] == "ERROR"),
            "warn_count": sum(1 for log in self.logs if log["level"] == "WARN"),
            "info_count": sum(1 for log in self.logs if log["level"] == "INFO"),
        }
class AcsToolWrapper:
    """
    直接调用 acs_simulate 工具，不依赖 evaluator。
    关键点：
    - 直接管理工具实例和调用逻辑
    - 不在每次 execute 后 release；由调用方在整个 bayesian 阶段结束后统一 release
    """
    def **init**(self, tool_instances: dict, extra_info: dict, unfixed_parameters: dict, convert_func: Optional[Callable] = None, convert_code: Optional[str] = None, log_collector: Optional[LogCollector] = None):
        """
        Args:
            tool_instances: 工具实例字典，格式为 {tool_name: {"instance": tool_instance}}
            extra_info: 额外信息，包含 tools_kwargs 等
            unfixed_parameters: 未固定参数
            convert_func: 参数转换函数
            convert_code: 参数转换代码
            log_collector: 日志收集器
        """
        self._tool_instances = tool_instances
        self._extra_info = extra_info or {}
        self._unfixed_parameters = unfixed_parameters or {}
        self._unfixed_parameter_names = list(self._unfixed_parameters.keys())
        self._convert_func = convert_func
        self._convert_code = convert_code  # 保存转换代码的原始文本
        self._log_collector = log_collector or LogCollector()
        # 只需要 acs_simulate，一个工具一条 instance_id
        self._tool_name = "acs_simulate"
        self._context_instance_id_dict = {self._tool_name: None}
        # 用于保存最后一次转换后的原始参数（用于结果处理）
        self._last_converted_params = None
        # 用于保存所有仿真的原始数据
        self._simulation_raw_data = []
    def _format_variables(self, parameters: dict) -> dict:
        variables = {}
        for key in self._unfixed_parameter_names:
            if key not in parameters:
                self._log_collector.error(
                    f"Key '{key}' not in parameters",
                    {
                        "expected_keys": sorted(self._unfixed_parameter_names),
                        "actual_keys": sorted(parameters.keys()),
                        "missing_key": key,
                    }
                )
                raise ValueError(f"Key '{key}' not in parameters. Expected keys: {sorted(self._unfixed_parameter_names)}, Actual keys: {sorted(parameters.keys())}")
            try:
                # 处理参数值：如果是字符串（带单位），先提取数值部分
                param_value = parameters[key]
                if isinstance(param_value, str):
                    # 如果是字符串，尝试提取数值部分（去掉单位）
                    import re
                    match = re.match(r'^([+-]?(\d+(\.\d*)?|\.\d+)([eE][+-]?\d+)?)', param_value)
                    if match:
                        param_value = float(match.group(1))
                    else:
                        param_value = float(param_value)
                else:
                    param_value = float(param_value)
                if key.startswith("Res"):
                    unit = "k"
                elif key.startswith("Cap"):
                    unit = "p"
                else:
                    unit = "u"
                formatted_value = str(smart_round(float(param_value)))
                variables[key] = formatted_value + unit
            except (ValueError, TypeError) as e:
                self._log_collector.exception(
                    f"Failed to format {key} with value {parameters[key]}",
                    e,
                    {
                        "key": key,
                        "value": parameters[key],
                        "value_type": type(parameters[key]).__name__,
                    }
                )
                raise
        return variables
    async def execute(self, **parameters):
        """
        返回 (score, performance_dict_or_none, performance_raw)
        如果提供了 stage1res 和转换函数，会将新参数空间的参数转换为原始参数空间的参数
        """
        # 保存转换前的参数（用于打印）
        original_parameters = parameters.copy()
        # 如果提供了转换函数，先将新参数空间的参数转换为原始参数空间的参数
        if self._convert_func is not None:
            try:
                # 检查函数签名，决定如何调用
                import inspect
                sig = inspect.signature(self._convert_func)
                param_names = list(sig.parameters.keys())
                # 判断函数期望的参数类型
                # 如果函数只有一个参数，且该参数名不在传入的参数字典的键中
                # 说明函数期望接收整个字典作为单个参数（如 calculate_dependent_params(indep_params)）
                first_param_name = param_names[0]
                if len(param_names) == 1:
                    if first_param_name not in parameters:
                        # 函数期望单个字典参数，传入整个字典
                        converted_parameters = self._convert_func(parameters)
                    else:
                        # 函数期望的关键字参数名正好在参数字典中，使用 **parameters
                        converted_parameters = self._convert_func(**parameters)
                else:
                    # 函数期望多个参数
                    # 检查第一个参数名是否在参数字典中
                    if first_param_name not in parameters:
                        # 第一个参数期望接收整个字典（如 calculate_parameters(ind_params, mode='high_performance')）
                        # 需要检查是否有其他参数需要传递
                        call_kwargs = {first_param_name: parameters}
                        # 检查其他参数是否有默认值或需要传递
                        for param_name in param_names[1:]:
                            param = sig.parameters[param_name]
                            if param.default != inspect.Parameter.empty:
                                # 有默认值，可以不传
                                continue
                            elif param_name in parameters:
                                # 参数在字典中，需要传递
                                call_kwargs[param_name] = parameters[param_name]
                        converted_parameters = self._convert_func(**call_kwargs)
                    else:
                        # 函数期望的关键字参数名都在参数字典中，使用 **parameters 展开为关键字参数
                        converted_parameters = self._convert_func(**parameters)
                # 如果转换函数返回的不是字典，报错并返回
                if not isinstance(converted_parameters, dict):
                    self._log_collector.error(
                        "转换函数返回的不是字典",
                        {
                            "original_parameters": original_parameters,
                            "return_type": type(converted_parameters).__name__,
                            "return_value": str(converted_parameters)[:500],
                        }
                    )
                    return 0.0, {"error": "转换函数返回的不是字典"}, ""
                # 映射转换后的参数键名到期望的键名
                expected_keys = set(self._unfixed_parameter_names)
                mapped_parameters = _map_parameter_keys(converted_parameters, expected_keys)
                # 验证转换后的参数：只检查缺失的键，允许多余的键
                mapped_keys = set(mapped_parameters.keys())
                missing_keys = expected_keys - mapped_keys
                if missing_keys:
                    extra_keys = mapped_keys - expected_keys
                    self._log_collector.error(
                        "转换后的参数空间缺少必需的参数键",
                        {
                            "original_parameters": original_parameters,
                            "converted_parameters": converted_parameters,
                            "mapped_parameters": mapped_parameters,
                            "expected_keys": sorted(expected_keys),
                            "mapped_keys": sorted(mapped_keys),
                            "missing_keys": sorted(missing_keys),
                            "extra_keys": sorted(extra_keys) if extra_keys else [],
                        }
                    )
                    return 0.0, {"error": f"转换后的参数空间缺少必需的参数键: {sorted(missing_keys)}"}, ""
                # 检查是否有多余的键（仅记录信息，不报错）
                extra_keys = mapped_keys - expected_keys
                if extra_keys:
                    self._log_collector.info(
                        "转换后的参数包含多余的键（已忽略）",
                        {
                            "extra_keys": sorted(extra_keys),
                        }
                    )
                # 保存映射后的参数（用于结果处理）
                # 只保留期望的键，移除多余的键
                final_parameters = {key: mapped_parameters[key] for key in expected_keys}
                self._last_converted_params = final_parameters.copy()
                parameters = final_parameters
            except Exception as e:
                details = {
                    "original_parameters": original_parameters,
                }
                # 记录转换函数的原始代码和签名
                if self._convert_code:
                    details["convert_code"] = self._convert_code
                # 记录函数签名信息
                if self._convert_func:
                    import inspect
                    try:
                        sig = inspect.signature(self._convert_func)
                        details["function_signature"] = f"{self._convert_func.__name__}{sig}"
                        details["expected_params"] = list(sig.parameters.keys())
                        details["actual_params"] = list(original_parameters.keys())
                        # 分析参数不匹配
                        expected_params = set(sig.parameters.keys())
                        actual_params = set(original_parameters.keys())
                        missing_params = expected_params - actual_params
                        extra_params = actual_params - expected_params
                        if missing_params:
                            details["missing_params"] = sorted(missing_params)
                        if extra_params:
                            details["extra_params"] = sorted(extra_params)
                    except Exception as sig_error:
                        details["signature_error"] = str(sig_error)
                self._log_collector.exception("参数转换失败", e, details)
                return 0.0, {"error": f"参数转换失败: {e}"}, ""
        else:
            self._last_converted_params = None
        # 格式化参数，如果失败则返回错误
        try:
            arguments = {"variables": self._format_variables(parameters)}
        except Exception as e:
            self._log_collector.exception(
                "格式化参数失败",
                e,
                {
                    "parameters": parameters,
                }
            )
            return 0.0, {"error": f"格式化参数失败: {e}"}, ""
        # 关键修复：每次调用时都传入 None 作为 instance_id，强制创建新实例
        # 这样可以确保每次调用都是独立的状态，避免工具实例复用导致的结果相同问题
        # 对于贝叶斯优化场景，每次调用都应该使用新的参数，所以强制创建新实例是必要的
        # 创建一个临时的 context_instance_id_dict，将 instance_id 设置为 None，强制创建新实例
        temp_context_instance_id_dict = {self._tool_name: None}
        try:
            # 直接调用工具，参考 base_evaluator._execute_tool_calls 的逻辑
            if self._tool_name not in self._tool_instances:
                performance_raw = f"Error: 工具 '{self._tool_name}' 未注册。"
            else:
                try:
                    # 获取工具实例及其额外参数
                    tool_instance = self._tool_instances[self._tool_name]["instance"]
                    # 动态更新 create_kwargs
                    if "tools_kwargs" in self._extra_info and self._tool_name in self._extra_info["tools_kwargs"]:
                        create_kwargs = self._extra_info["tools_kwargs"][self._tool_name].get("create_kwargs", {})
                    else:
                        create_kwargs = {}
                    # 调用工具的 create 和 execute 方法
                    create_result = await tool_instance.create(temp_context_instance_id_dict[self._tool_name], **create_kwargs)
                    # 兼容返回一个值或两个值的情况
                    if isinstance(create_result, tuple):
                        current_instance_id, current_tool_create_response = create_result
                    else:
                        current_instance_id = create_result
                        current_tool_create_response = None
                    temp_context_instance_id_dict[self._tool_name] = current_instance_id
                    tool_result = await tool_instance.execute(current_instance_id, arguments)
                    # tool_result 格式: (tool_response, tool_reward, tool_metrics)
                    tool_response, tool_reward, tool_metrics = tool_result
                    performance_raw = str(tool_response)
                except Exception as e:
                    performance_raw = f"Error calling {self._tool_name}: {str(e)}"
            # 调用完成后，释放新创建的实例，避免资源泄漏
            new_instance_id = temp_context_instance_id_dict.get(self._tool_name)
            if new_instance_id and self._tool_instances:
                tool_instance = self._tool_instances.get(self._tool_name, {}).get("instance")
                if tool_instance:
                    try:
                        await tool_instance.release(new_instance_id)
                    except Exception as e:
                        self._log_collector.exception(
                            f"Failed to release instance {new_instance_id}",
                            e,
                            {
                                "instance_id": new_instance_id,
                                "tool_name": self._tool_name,
                            }
                        )
            # 工具 server 返回失败时，content 往往是错误字符串（不是 dict），此时不要继续解析
            if (
                performance_raw.startswith("Error")
                or performance_raw.startswith("Invalid response")
                or "Internal Server Error" in performance_raw
                or "failed to call tool" in performance_raw
            ):
                self._log_collector.error(
                    "工具调用返回错误",
                    {
                        "performance_raw": performance_raw,
                        "tool_name": self._tool_name,
                    }
                )
                # 保存原始数据
                self._simulation_raw_data.append({
                    "parameters": original_parameters,
                    "converted_parameters": self._last_converted_params,
                    "performance_raw": performance_raw,
                    "score": 0.0,
                    "performance": {"error": performance_raw},
                    "timestamp": datetime.now().isoformat()
                })
                return 0.0, {"error": performance_raw}, performance_raw
            try:
                performance_str = performance_raw.replace("Simulation Result:\n", "").replace("Simulation Result:", "").strip()
                performance = ast.literal_eval(performance_str)
                identity = self._extra_info["tools_kwargs"][self._tool_name]["create_kwargs"]["identity"]
                score = calculate_score(performance, identity)
                # 保存原始数据
                self._simulation_raw_data.append({
                    "parameters": original_parameters,
                    "converted_parameters": self._last_converted_params,
                    "performance_raw": performance_raw,
                    "score": score,
                    "performance": performance,
                    "timestamp": datetime.now().isoformat()
                })
                return score, performance, performance_raw
            except Exception as parse_error:
                self._log_collector.exception(
                    "解析工具返回结果失败",
                    parse_error,
                    {
                        "performance_raw": performance_raw,
                        "tool_name": self._tool_name,
                    }
                )
                # 保存原始数据
                self._simulation_raw_data.append({
                    "parameters": original_parameters,
                    "converted_parameters": self._last_converted_params,
                    "performance_raw": performance_raw,
                    "score": 0.0,
                    "performance": {"error": f"解析结果失败: {parse_error}", "raw": performance_raw},
                    "timestamp": datetime.now().isoformat()
                })
                return 0.0, {"error": f"解析结果失败: {parse_error}", "raw": performance_raw}, performance_raw
        except Exception as e:
            raw = performance_raw if "performance_raw" in locals() else None
            self._log_collector.exception(
                "执行acs_tool失败",
                e,
                {
                    "tool_name": self._tool_name,
                    "performance_raw": raw,
                }
            )
            # 保存原始数据
            self._simulation_raw_data.append({
                "parameters": original_parameters if "original_parameters" in locals() else parameters,
                "converted_parameters": self._last_converted_params,
                "performance_raw": raw if raw else "",
                "score": 0.0,
                "performance": {"error": f"{type(e).__name__}: {e}", "raw": raw},
                "timestamp": datetime.now().isoformat()
            })
            return 0.0, {"error": f"{type(e).__name__}: {e}", "raw": raw}, raw if raw else ""
    async def release(self):
        """
        统一释放工具实例（避免在每次 execute 后释放导致重复 create/竞争问题）
        """
        for tool_name, instance_id in self._context_instance_id_dict.items():
            if instance_id and tool_name in self._tool_instances:
                tool_instance = self._tool_instances[tool_name]["instance"]
                await tool_instance.release(instance_id)
        self._context_instance_id_dict = {self._tool_name: None}
    def get_simulation_raw_data(self) -> List[Dict[str, Any]]:
        """
        获取所有仿真的原始数据
        Returns:
            所有仿真原始数据的列表
        """
        return self._simulation_raw_data.copy()
    def clear_simulation_raw_data(self):
        """
