# check valid 分为两部分：1.验证基础有效性，即参数空间、convert func是否满足原始优化问题的限制；2.验证新区间内是否能有效采样到非0值
class CheckValidTool(BaseTool):
    def **init**(self, config: dict, tool_schema: OpenAIFunctionToolSchema):
