    def _format_parameter_value(self, param_name: str, param_value: Any) -> str:
        """
        格式化参数值，添加单位并应用smart_round
        如果格式化失败，返回原始字符串
        Args:
            param_name: 参数名
            param_value: 参数值（可以是数字或字符串）
        Returns:
            格式化后的字符串，格式为 "值+单位"
        """
        try:
            # 处理参数值：如果是字符串（带单位），先提取数值部分
            if isinstance(param_value, str):
                # 如果是字符串，尝试提取数值部分（去掉单位，支持科学计数法）
                import re
                match = re.match(r'^([+-]?(\d+(\.\d*)?|\.\d+)([eE][+-]?\d+)?)', param_value)
                if match:
                    param_value = float(match.group(1))
                else:
                    param_value = float(param_value)
            else:
                param_value = float(param_value)
            # 根据参数名确定单位
            if param_name.startswith("Res"):
                unit = "k"
            elif param_name.startswith("Cap"):
                unit = "p"
            else:
                unit = "u"
            formatted_value = str(smart_round(float(param_value)))
            return formatted_value + unit
        except (ValueError, TypeError):
            # 如果格式化失败，返回原始字符串
            return str(param_value)
    def _format_performance_value(self, value: Any) -> str:
        """
        格式化performance中的数值，应用smart_round
        如果格式化失败，返回原始字符串
        Args:
            value: 需要格式化的值（可以是数字或字符串）
        Returns:
            格式化后的字符串
        """
        try:
            if isinstance(value, str):
                # 如果是字符串，尝试提取数值部分（支持科学计数法）
                import re
                match = re.match(r'^([+-]?(\d+(\.\d*)?|\.\d+)([eE][+-]?\d+)?)', value)
                if match:
                    num_value = float(match.group(1))
                    formatted_value = str(smart_round(num_value))
                    # 如果原字符串有单位或其他后缀，保留它们
                    suffix = value[match.end():]
                    return formatted_value + suffix
                else:
                    # 如果无法提取数值，尝试直接转换
                    num_value = float(value)
                    return str(smart_round(num_value))
            else:
                num_value = float(value)
                return str(smart_round(num_value))
        except (ValueError, TypeError):
            # 如果格式化失败，返回原始字符串
            return str(value)
    def _format_performance_raw(self, performance_raw: str) -> str:
        """
        格式化performance_raw字符串中的数值
        如果performance_raw是JSON格式，解析并格式化其中的数值
        如果格式化失败，返回原始字符串
        Args:
            performance_raw: 原始performance字符串
        Returns:
            格式化后的字符串
        """
        if not performance_raw:
            return performance_raw
        try:
            # 尝试解析为JSON
            if performance_raw.startswith("Simulation Result:"):
                json_str = performance_raw[len("Simulation Result:"):].strip()
                try:
                    performance_dict = json.loads(json_str)
                    # 递归格式化字典中的所有数值
                    formatted_dict = self._format_dict_values(performance_dict)
                    return f"Simulation Result:\n{json.dumps(formatted_dict, ensure_ascii=False)}"
                except json.JSONDecodeError:
                    # 如果不是有效的JSON，返回原始字符串
                    return performance_raw
            else:
                # 如果不是JSON格式，返回原始字符串
                return performance_raw
        except Exception:
            # 如果格式化失败，返回原始字符串
            return performance_raw
    def _format_dict_values(self, data: Any) -> Any:
        """
        递归格式化字典中的所有数值（包括字符串类型的数字）
        Args:
            data: 需要格式化的数据（可以是字典、列表、数字、字符串等）
        Returns:
            格式化后的数据
        """
        if isinstance(data, dict):
            return {k: self._format_dict_values(v) for k, v in data.items()}
        elif isinstance(data, list):
            return [self._format_dict_values(item) for item in data]
        elif isinstance(data, (int, float)):
            return self._format_performance_value(data)
        elif isinstance(data, str):
            # 尝试将字符串转换为数字并格式化
            # 如果转换失败，返回原始字符串
            return self._format_performance_value(data)
        else:
            return data
    @rollout_trace_op
    async def execute(self, instance_id: str, parameters: dict[str, Any], **kwargs) -> tuple[str, float, dict]:
        """
        parameters 约定：
        - parameters["ParameterSpace"]: dict
        - parameters["ParameterRelationCode"]: string
        - parameters["initParameterSpace"]: dict
        """
        async with self.semaphore:
            init_parameters = self._instance_dict[instance_id]["unfixed_parameters"]
            space_star = parameters["ParameterSpace"]["space"]
            convert_code = parameters["ParameterRelationCode"]
            # print("\n\nconvert_code: ", convert_code, "\n\n")
            # print("\n\nspace_star: ", space_star, "\n\n")
            # print("\n\ninit_parameters: ", init_parameters, "\n\n")
            convert_func = None
            if convert_code:
                try:
                    # 创建一个命名空间来执行代码
                    code_namespace = {}
                    exec(convert_code, code_namespace)
                    # 查找函数（通常是 calculate_parameters, calculate_dependent_params 等）
                    for func_name in ['calculate_parameters', 'calculate_dependent_params', 'calc_all_params',
                                    'calculate_dependent_parameters', 'calculate_interval_point_score']:
                        if func_name in code_namespace:
                            convert_func = code_namespace[func_name]
                            break
                    if convert_func is None:
                        # 如果没有找到标准函数名，尝试查找第一个可调用对象
                        for obj in code_namespace.values():
                            if callable(obj) and not isinstance(obj, type):
                                convert_func = obj
                                break
                except Exception as e:
                    log_collector = kwargs.get("log_collector")
                    if log_collector:
                        log_collector.exception("无法从 stage1res 中提取转换函数", e, {
                            "convert_code_preview": convert_code[:500] if convert_code else None,
                        })
                    convert_func = None
            # 验证 convert_func 的有效性
            is_valid = True
            error_summary = {
                "func_execution_failures": [],  # convert_func 执行失败的错误信息
                "return_type_errors": 0,  # 返回值不是字典类型的次数
                "missing_params": set(),  # 缺少的参数集合
                "out_of_range_params": {}  # 超出范围的参数: {param_name: {"count": int, "example": (value, min, max)}}
            }
            if convert_func is not None:
                try:
                    # 获取原始空间的所有参数名
                    original_param_names = set(init_parameters.keys())
                    # 在新空间采样多个点进行验证
                    num_samples = 10
                    for sample_idx in range(num_samples):
                        # 在新空间随机采样一个点
                        sample_point = {}
                        for param_name, param_range in space_star.items():
                            if len(param_range) == 2:
                                min_val, max_val = param_range[0], param_range[1]
                                # 随机采样
                                sample_value = random.uniform(min_val, max_val)
                                sample_point[param_name] = sample_value
                        # 使用 convert_func 映射到原始空间
                        try:
                            mapped_point = convert_func(sample_point)
                        except Exception as e:
                            is_valid = False
                            error_summary["func_execution_failures"].append(str(e))
                            continue
                        # 检查映射后的结果是否为字典
                        if not isinstance(mapped_point, dict):
                            is_valid = False
                            error_summary["return_type_errors"] += 1
                            continue
                        # 检查映射后的点是否包含所有原始空间参数
                        mapped_param_names = set(mapped_point.keys())
                        missing_params = original_param_names - mapped_param_names
                        if missing_params:
                            is_valid = False
                            error_summary["missing_params"].update(missing_params)
                            continue
                        # 检查映射后的值是否在原始空间范围内
                        for param_name in original_param_names:
                            mapped_value = mapped_point[param_name]
                            min_val, max_val = init_parameters[param_name][0], init_parameters[param_name][1]
                            if not (min_val <= mapped_value <= max_val):
                                is_valid = False
                                if param_name not in error_summary["out_of_range_params"]:
                                    error_summary["out_of_range_params"][param_name] = {
                                        "count": 0,
                                        "example": (mapped_value, min_val, max_val)
                                    }
                                error_summary["out_of_range_params"][param_name]["count"] += 1
                                break
                except Exception as e:
                    is_valid = False
                    error_summary["func_execution_failures"].append(f"验证过程异常: {str(e)}")
            # 如果基础有效性验证失败，直接返回
            if not is_valid:
                # 归纳错误信息
                error_parts = []
                # convert_func 执行失败
                if error_summary["func_execution_failures"]:
                    unique_errors = list(set(error_summary["func_execution_failures"]))
                    if len(unique_errors) == 1:
                        error_parts.append(f"convert_func 执行失败: {unique_errors[0]}")
                    else:
                        error_parts.append(f"convert_func 执行失败: {unique_errors[0]}")
                # 返回值类型错误
                if error_summary["return_type_errors"] > 0:
                    error_parts.append(f"convert_func 返回值不是字典类型")
                # 缺少参数
                if error_summary["missing_params"]:
                    missing_list = sorted(list(error_summary["missing_params"]))
                    error_parts.append(f"映射后的点缺少参数: {', '.join(missing_list)}")
                # 超出范围的参数
                if error_summary["out_of_range_params"]:
                    out_of_range_list = []
                    for param_name, info in sorted(error_summary["out_of_range_params"].items()):
                        value, min_val, max_val = info["example"]
                        out_of_range_list.append(
                            f"{param_name}(值={value:.4f} 超出范围[{min_val}, {max_val}])"
                        )
                    error_parts.append(f"参数超出原始空间范围: {'; '.join(out_of_range_list)}")
                error_msg = "; ".join(error_parts)
                # print("\n\nerror_msg: ", error_msg, "\n\n")
                return f"check valid result: False. {error_msg}", 0, {}
            # 基础有效性验证通过后，进行新的验证：在新空间上均匀采样10个点，并发仿真
            # 根据当前实例信息重新生成acs工具实例
            # print("开始仿真验证")
            identity = self._instance_dict[instance_id]
            extra_info = {
                "tools_kwargs": {
                    self.acs_tool_name: {
                        "create_kwargs": {
                            "identity": identity
                        }
                    }
                }
            }
            tool_instances = {
                self.acs_tool_name: {
                    "instance": self.acs_tool_instance
                }
            }
            # 创建 AcsToolWrapper
            log_collector = LogCollector()
            acs_tool = AcsToolWrapper(
                tool_instances=tool_instances,
                extra_info=extra_info,
                unfixed_parameters=init_parameters,
                convert_func=convert_func,
                convert_code=convert_code,
                log_collector=log_collector
            )
            # 在新空间上均匀采样10个点
            num_samples = 10
            sample_points = []
            param_names = list(space_star.keys())
            # 使用均匀采样：对每个参数，将区间分成 num_samples 份，然后组合
            # 为了确保采样点均匀分布，我们使用简单的均匀间隔采样
            for i in range(num_samples):
                sample_point = {}
                for param_name in param_names:
                    param_range = space_star[param_name]
                    if len(param_range) == 2:
                        min_val, max_val = param_range[0], param_range[1]
                        # 均匀采样：将区间分成 num_samples 份，选择第 i 份的中点
                        # 使用 (i + 0.5) / num_samples 来确保采样点在区间内均匀分布
                        sample_value = min_val + (max_val - min_val) * (i + 0.5) / num_samples
                        sample_point[param_name] = sample_value
                sample_points.append(sample_point)
            # 并发调用工具仿真（使用 AcsToolWrapper）
            async def simulate_point(sample_point: dict) -> tuple[float, dict, dict, str]:
                """仿真单个点，返回 (score, performance, original_params, performance_raw)"""
                original_params = sample_point.copy()
                performance_raw = ""
                try:
                    # 使用 AcsToolWrapper.execute 调用工具
                    # AcsToolWrapper 会自动处理参数转换、格式化等
                    # 现在返回 (score, performance, performance_raw)
                    score, performance, performance_raw = await acs_tool.execute(**sample_point)
                    return score, performance, original_params, performance_raw
                except Exception as e:
                    return 0.0, {"error": f"{type(e).__name__}: {e}"}, original_params, performance_raw if 'performance_raw' in locals() else ""
            # 并发执行所有采样点的仿真
            results = await asyncio.gather(*[simulate_point(point) for point in sample_points], return_exceptions=True)
            # print("results: ", results)
            # 统计超过阈值的点的数量，并记录每个点的详细信息
            valid_count = 0
            valid_points = []  # 有效点列表
            invalid_points = []  # 无效点列表
            for idx, result in enumerate(results):
                if isinstance(result, Exception):
                    invalid_points.append({
                        "index": idx + 1,
                        "parameters": sample_points[idx],
                        "error": str(result),
                        "performance_raw": "",
                        "score": 0.0
                    })
                    continue
                score, performance, original_params, performance_raw = result
                point_info = {
                    "index": idx + 1,
                    "parameters": original_params,
                    "performance_raw": performance_raw if performance_raw else "",  # 限制长度
                    "score": score
                }
                if score > self.SCORE_THRESHOLD:
                    valid_count += 1
                    valid_points.append(point_info)
                else:
                    # 获取错误信息
                    error_msg = ""
                    if isinstance(performance, dict) and "error" in performance:
                        error_msg = performance["error"]
                    point_info["error"] = error_msg
                    invalid_points.append(point_info)
            # 获取所有仿真的原始数据
            simulation_raw_data = acs_tool.get_simulation_raw_data()
            # 释放 AcsToolWrapper 资源
            try:
                await acs_tool.release()
            except Exception as e:
                # 释放失败不影响结果
                pass
            # 判断验证是否通过：10个点中超过阈值的点大于等于10个
            if valid_count >= 8:
                # 保存仿真原始数据到 metrics
                metrics = {
                    "simulation_raw_data": simulation_raw_data
                }
                return f"check valid result: True", 0, metrics
            else:
                # 构建详细的错误信息
                error_parts = [
                    "check valid result: False",
                    "",
                    "✅ 基础有效性验证通过：新空间经转换函数映射回原空间后满足原始范围限制",
                    f"❌ 新空间内采样验证失败：10个采样点中只有{valid_count}个有效点（需要>=8个，阈值={self.SCORE_THRESHOLD}）",
                    ""
                ]
                # 罗列有效点
                if valid_points:
                    total_valid = len(valid_points)
                    display_count = min(3, total_valid)
                    if total_valid > 3:
                        error_parts.append(f"📊 有效点（共{total_valid}个，仅显示前{display_count}个）：")
                    else:
                        error_parts.append(f"📊 有效点（{total_valid}个）：")
                    for point in valid_points[:display_count]:
                        error_parts.append(f"  点{point['index']}:")
                        # 格式化参数，使其更易读（使用smart_round并添加单位）
                        params_str_list = []
                        for k, v in point['parameters'].items():
                            formatted_value = self._format_parameter_value(k, v)
                            params_str_list.append(f"{k}={formatted_value}")
                        params_str = ", ".join(params_str_list)
                        error_parts.append(f"    参数: {{{params_str}}}")
                        # 格式化得分
                        formatted_score = self._format_performance_value(point['score'])
                        error_parts.append(f"    得分: {formatted_score}")
                        if point['performance_raw']:
                            # 格式化performance_raw中的数值
                            formatted_performance = self._format_performance_raw(point['performance_raw'])
                            error_parts.append(f"    performance_raw: {formatted_performance}")
                        error_parts.append("")
                # 罗列无效点
                if invalid_points:
                    total_invalid = len(invalid_points)
                    display_count = min(3, total_invalid)
                    if total_invalid > 3:
                        error_parts.append(f"❌ 无效点（共{total_invalid}个，仅显示前{display_count}个）：")
                    else:
                        error_parts.append(f"❌ 无效点（{total_invalid}个）：")
                    for point in invalid_points[:display_count]:
                        error_parts.append(f"  点{point['index']}:")
                        # 格式化参数，使其更易读（使用smart_round并添加单位）
                        params_str_list = []
                        for k, v in point['parameters'].items():
                            formatted_value = self._format_parameter_value(k, v)
                            params_str_list.append(f"{k}={formatted_value}")
                        params_str = ", ".join(params_str_list)
                        error_parts.append(f"    参数: {{{params_str}}}")
                        # 格式化得分
                        formatted_score = self._format_performance_value(point['score'])
                        error_parts.append(f"    得分: {formatted_score}")
                        if point.get('error'):
                            error_parts.append(f"    错误: {point['error']}")
                        if point['performance_raw']:
                            # 格式化performance_raw中的数值
                            formatted_performance = self._format_performance_raw(point['performance_raw'])
                            error_parts.append(f"    performance_raw: {formatted_performance}")
                        error_parts.append("")
                error_msg = "\n".join(error_parts)
                # 保存仿真原始数据到 metrics
                metrics = {
                    "simulation_raw_data": simulation_raw_data
                }
                return error_msg, 0, metrics
def validate_parameter_space_and_code(init_parameters: dict, space_star: dict, convert_code: str) -> tuple[bool, str]:
    """
    验证参数空间和转换代码的核心功能
    Args:
        init_parameters: 原始参数空间，格式为 {param_name: [min, max]}
        space_star: 新参数空间，格式为 {param_name: [min, max]}
        convert_code: 参数转换代码字符串
    Returns:
        (is_valid, error_msg): 是否有效，错误信息（如果无效）
    """
    # 提取转换函数
    convert_func = None
    if convert_code:
        try:
            code_namespace = {}
            exec(convert_code, code_namespace)
            # 查找函数
            for func_name in ['calculate_parameters', 'calculate_dependent_params', 'calc_all_params',
                            'calculate_dependent_parameters', 'calculate_interval_point_score']:
                if func_name in code_namespace:
                    convert_func = code_namespace[func_name]
                    break
            if convert_func is None:
                # 如果没有找到标准函数名，尝试查找第一个可调用对象
                for obj in code_namespace.values():
                    if callable(obj) and not isinstance(obj, type):
                        convert_func = obj
                        break
        except Exception as e:
            return False, f"无法从代码中提取转换函数: {str(e)}"
    if convert_func is None:
        return False, "未找到转换函数"
    # 验证 convert_func 的有效性
    is_valid = True
    error_summary = {
        "func_execution_failures": [],
        "return_type_errors": 0,
        "missing_params": set(),
        "out_of_range_params": {}
    }
    try:
        original_param_names = set(init_parameters.keys())
        # 在新空间采样多个点进行验证
        num_samples = 10
        for sample_idx in range(num_samples):
            # 在新空间随机采样一个点
            sample_point = {}
            for param_name, param_range in space_star.items():
                if len(param_range) == 2:
                    min_val, max_val = param_range[0], param_range[1]
                    sample_value = random.uniform(min_val, max_val)
                    sample_point[param_name] = sample_value
            # 使用 convert_func 映射到原始空间
            try:
                mapped_point = convert_func(sample_point)
            except Exception as e:
                is_valid = False
                error_summary["func_execution_failures"].append(str(e))
                continue
            # 检查映射后的结果是否为字典
            if not isinstance(mapped_point, dict):
                is_valid = False
                error_summary["return_type_errors"] += 1
                continue
            # 检查映射后的点是否包含所有原始空间参数
            mapped_param_names = set(mapped_point.keys())
            missing_params = original_param_names - mapped_param_names
            if missing_params:
                is_valid = False
                error_summary["missing_params"].update(missing_params)
                continue
            # 检查映射后的值是否在原始空间范围内
            for param_name in original_param_names:
                mapped_value = mapped_point[param_name]
                min_val, max_val = init_parameters[param_name][0], init_parameters[param_name][1]
                if not (min_val <= mapped_value <= max_val):
                    is_valid = False
                    if param_name not in error_summary["out_of_range_params"]:
                        error_summary["out_of_range_params"][param_name] = {
                            "count": 0,
                            "example": (mapped_value, min_val, max_val)
                        }
                    error_summary["out_of_range_params"][param_name]["count"] += 1
                    break
