def _ensure_gene_list(x: Any, label: str = "gene") -> List[Dict[str, Any]]:
    if not isinstance(x, list):
        raise ValueError(f"{label} must be list[turn], got {type(x)}")
    for i, it in enumerate(x):
        if not isinstance(it, dict):
            raise ValueError(f"{label}[{i}] must be dict, got {type(it)}")
    return x  # type: ignore[return-value]

def _gene_last_parameters(gene: Any, *, label: str = "gene") -> Dict[str, Any]:
    gene_list = _ensure_gene_list(gene, label=label)
    for it in reversed(gene_list):
        params = it.get("parameters")
        if isinstance(params, dict):
            return params
    raise ValueError(f"{label} has no turn with dict parameters")

def _extract_gene_from_episode_obj(ep: Dict[str, Any]) -> Optional[List[Dict[str, Any]]]:
    """
    从 initial episode 里抽出 gene-list：
      - ep["initial_parameters"] (preferred)
      - ep["variables"] (如果你的 initial 文件把 gene 放在 variables)
    """
    if not isinstance(ep, dict):
        return None
    ip = ep.get("initial_parameters")
    if isinstance(ip, list):
        return _ensure_gene_list(ip, label="episode.initial_parameters")
    v = ep.get("variables")
    if isinstance(v, list):
