from internbootcamp.utils.load_tool_from_config import load_tool_from_config
from internbootcamp.src.base_interaction import BaseInteraction

def _load_tools_from_yaml(yaml_path: str) -> Dict[str, Dict[str, Any]]:
    with open(yaml_path, "r", encoding="utf-8") as f:
        config = yaml.safe_load(f)
    tools_config = config.get("tools", [])
    tool_instances: Dict[str, Dict[str, Any]] = {}
    for tool_cfg in tools_config:
        func_name = None
        try:
            func_name, schema, tool_instance = load_tool_from_config(tool_cfg)
            tool_instances[func_name] = {"instance": tool_instance, "schema": schema}
        except Exception as e:
            # 不要“吞掉”异常，否则后面只会看到 KeyError('checkValid')
            raise RuntimeError(
                f"Failed to load tool from config. func_name={func_name}, tool_cfg={tool_cfg}, err={e}"
            ) from e
    if not tool_instances:
        raise RuntimeError(f"No tools loaded from yaml: {yaml_path}")
    return tool_instances
class ACSInteraction(BaseInteraction):
    def __init__(self, config: dict[str, Any]):
        self.tool_instances = _load_tools_from_yaml(config["yaml_tool_path"])
        print("[ACSInteraction] Loaded tools:", list(self.tool_instances.keys()), flush=True)
        if "checkValid" not in self.tool_instances:
            raise RuntimeError(
                f"Tool 'checkValid' not found after loading. Available={list(self.tool_instances.keys())}"
            )
        super().__init__(config)
    async def start_interaction(
        self,
        instance_id: Optional[str] = None,
        identity: dict[str, Any] = None,
        **kwargs,
    ) -> str:
        return await super().start_interaction(instance_id, identity, **kwargs)
    def _extract_tag_content(self, content: str, tag: str) -> Optional[str]:
        """从后往前查找最后一个完整的标签对，确保提取到正确的标签内容"""
        start_tag = f"<{tag}>"
        end_tag = f"</{tag}>"
        # 找到最后一个开始标签的位置
        last_start_pos = content.rfind(start_tag)
        if last_start_pos == -1:
            return None
        # 从最后一个开始标签之后查找对应的结束标签
        search_start = last_start_pos + len(start_tag)
        end_pos = content.find(end_tag, search_start)
        if end_pos == -1:
            return None
        # 提取标签内容
        tag_content = content[search_start:end_pos].strip()
        return tag_content
    def _clean_json_string(self, json_str: str) -> str:
        """
        清理JSON字符串，去除注释并修复常见格式问题
        处理：
        1. 单行注释 (//)
        2. 单行注释 (#)
        3. 多行注释 (/* */)
        4. 尾随逗号
        5. 单引号转双引号（仅在非字符串上下文中）
        """
        if not json_str:
            return json_str
        lines = json_str.split("\n")
        cleaned_lines = []
        in_multiline_comment = False
        for line in lines:
            result_line = []
            i = 0
            in_string = False
            escape_next = False
            string_char = None  # 记录字符串的引号类型 (' 或 ")
            while i < len(line):
                char = line[i]
                if escape_next:
                    result_line.append(char)
                    escape_next = False
                    i += 1
                    continue
                if char == "\\":
                    result_line.append(char)
                    escape_next = True
                    i += 1
                    continue
                # 处理字符串开始/结束（支持单引号和双引号）
                if (char == '"' or char == "'") and not escape_next:
                    if not in_string:
                        # 字符串开始
                        in_string = True
                        string_char = char
                        result_line.append('"')  # JSON只支持双引号，统一转换为双引号
                    elif char == string_char:
                        # 字符串结束
                        in_string = False
                        string_char = None
                        result_line.append('"')
                    else:
                        # 字符串内的另一种引号
                        # 如果是单引号字符串内的双引号，需要转义
                        if string_char == "'" and char == '"':
                            result_line.append('\\"')
                        else:
                            result_line.append(char)
                    i += 1
                    continue
                if not in_string:
                    # 处理多行注释
                    if in_multiline_comment:
                        if i < len(line) - 1 and line[i : i + 2] == "*/":
                            in_multiline_comment = False
                            i += 2
                            continue
                        else:
                            i += 1
                            continue
                    # 检查单行注释 (//)
                    if i < len(line) - 1 and line[i : i + 2] == "//":
                        break
                    # 检查单行注释 (#)
                    elif char == "#":
                        break
                    # 检查多行注释开始
                    elif i < len(line) - 1 and line[i : i + 2] == "/*":
                        in_multiline_comment = True
                        i += 2
                        continue
                else:
                    # 在字符串内，其他字符直接添加
                    pass
                result_line.append(char)
                i += 1
            cleaned_line = "".join(result_line).rstrip()
            # 如果这一行有内容，就添加它（即使多行注释还在继续）
            # 只有当整行都在注释内时（result_line为空），才跳过这一行
            if cleaned_line:
                cleaned_lines.append(cleaned_line)
        result = "\n".join(cleaned_lines)
        # 处理尾随逗号（在对象和数组的最后一个元素后）
        # 使用更精确的正则，匹配 }, 或 ], 前面有空白字符的情况
        result = re.sub(r",(\s*[}\]])", r"\1", result)
        return result
    def _extract_parameter_space(
        self, content: str, debug: bool = False
    ) -> Tuple[Optional[List[Dict]], Optional[str]]:
        """
        提取ParameterSpace，返回(space_list, error_message)
        如果解析失败，error_message包含错误信息；如果成功，error_message为None
        """
        space_str = self._extract_tag_content(content, "ParameterSpace")
        if not space_str:
            return None, None
        # 首先尝试直接解析
        try:
            cleaned_space_str = self._clean_json_string(space_str)
            space_list = json.loads(cleaned_space_str)
            return space_list, None
        except Exception as e:
            error_msg = f"ParameterSpace JSON提取失败: {e}"
            if debug:
                print("=" * 80)
                print("🔴 DEBUG模式: ParameterSpace JSON提取失败，立刻终止")
                print("=" * 80)
                print(f"错误信息: {error_msg}")
                print(f"错误类型: {type(e).__name__}")
                import traceback
                print("\n完整堆栈跟踪:")
                print(f"{'─' * 80}")
                traceback.print_exc()
                print(f"{'─' * 80}")
                print("\n原始ParameterSpace标签内容:")
                print(space_str)
                print(f"{'─' * 80}")
                print("原始content")
                print(content)
                print("=" * 80)
                import sys
                sys.exit(1)
            else:
                print(error_msg)
            return None, error_msg
    def _extract_parameter_relation_code(
        self, content: str, debug: bool = False
    ) -> Tuple[Optional[str], Optional[str]]:
        """
        提取ParameterRelationCode，返回(code, error_message)
        如果提取失败，error_message包含错误信息；如果成功，error_message为None
        """
        code_str = self._extract_tag_content(content, "ParameterRelationCode")
        if not code_str:
            error_msg = "ParameterRelationCode标签未找到或为空"
            if debug:
                print("=" * 80)
                print("🔴 DEBUG模式: ParameterRelationCode提取失败，立刻终止")
                print("=" * 80)
                print(f"错误信息: {error_msg}")
                print("\n完整消息内容（前1000字符）:")
                print(f"{'─' * 80}")
                print(content[:1000])
                print(f"{'─' * 80}")
                print("=" * 80)
                import sys
                sys.exit(1)
            return None, error_msg
        return code_str, None
    async def generate_response(
        self, instance_id: str, messages: list[dict[str, Any]], **kwargs
    ) -> tuple[bool, str, float, dict[str, Any]]:
        """
        从 messages 中提取最后一个 assistant 消息，提取 ParameterSpace 和 ParameterRelationCode，
        调用工具执行验证，返回结果。
        返回:
            should_terminate_sequence: bool - 是否终止序列
            response_content: str - 响应内容（CheckValid格式）
            current_turn_score: float - 当前轮次分数
            additional_data: dict - 额外数据（包含 simulation_raw_data）
        """
        interaction_instance = self._instance_dict[instance_id]
        # 从 messages 中获取最后一个 assistant 消息的 content
        content = ""
        for i in range(len(messages) - 1, -1, -1):
            item = messages[i]
            if item.get("role") == "assistant":
                content = item.get("content", "")
                break
        # 检测到<END>、<End>或<end>都停止
        if re.search(r"<[Ee][Nn][Dd]>", content):
            return True, "", 0.0, {"simulation_raw_data": {}}
        # 如果没有工具实例，直接返回
        if not interaction_instance:
            return False, "No interations available", 0.0, {"simulation_raw_data": {}}
        # 这里就是你真正想输出的“工具名”，用于错误信息
        tool_name = "checkValid"
        try:
            parameter_space_list, space_error = self._extract_parameter_space(content)
            parameter_relation_code, relation_error = self._extract_parameter_relation_code(content)
            # 如果ParameterSpace解析失败，将其作为check valid的返回结果
            if space_error is not None:
                idx = 0
                try:
                    # 尝试从content中提取可能的idx
                    idx_match = re.search(r'"idx"\s*:\s*(\d+)', content)
                    if idx_match:
                        idx = int(idx_match.group(1))
                except Exception:
                    pass
                error_result = [{"idx": idx, "result": f"ParameterSpace解析失败: {space_error}"}]
                check_valid_content = (
                    f"<CheckValid>{json.dumps(error_result, ensure_ascii=False)}</CheckValid>"
                )
                return False, check_valid_content, 0.0, {"simulation_raw_data": {}}
            # 如果ParameterRelationCode解析失败，将其作为check valid的返回结果
            if relation_error is not None:
                idx = 0
                try:
                    # 尝试从content中提取可能的idx
                    idx_match = re.search(r'"idx"\s*:\s*(\d+)', content)
                    if idx_match:
                        idx = int(idx_match.group(1))
                except Exception:
                    pass
                error_result = [{"idx": idx, "result": f"ParameterRelationCode解析失败: {relation_error}"}]
                check_valid_content = (
                    f"<CheckValid>{json.dumps(error_result, ensure_ascii=False)}</CheckValid>"
                )
                return False, check_valid_content, 0.0, {"simulation_raw_data": {}}
            if parameter_space_list is None or parameter_relation_code is None:
                return True, "", 0.0, {"simulation_raw_data": {}}
            # 将parameter_space_list标准化为列表格式
            spaces_to_check = []
            if isinstance(parameter_space_list, list):
                spaces_to_check = parameter_space_list
            elif isinstance(parameter_space_list, dict):
                spaces_to_check = [parameter_space_list]
            if len(spaces_to_check) == 0:
                return True, "", 0.0, {"simulation_raw_data": {}}
            # interaction内需要调用tool
            print("self.tool_instances keys: ", self.tool_instances.keys())
            checkValid_instance = self.tool_instances[tool_name]["instance"]
            create_kwargs = {"identity": interaction_instance["identity"][tool_name]}
            create_result = await checkValid_instance.create(instance_id, **create_kwargs)
            if isinstance(create_result, tuple):
                current_instance_id, current_interation_create_response = create_result
            else:
                current_instance_id = create_result
                current_interation_create_response = None
            # 为每个space执行check valid
            all_interation_results = []
            # 收集仿真的原始数据，按照space idx组织
            # 结构: {space_0: {parameter_space: {...}, parameter_relation_code: "...", simulation_data: [...]}, ...}
            simulation_raw_data = {}
            for parameter_space_dict in spaces_to_check:
                try:
                    interation_parameters = {
                        "ParameterSpace": parameter_space_dict,
                        "ParameterRelationCode": parameter_relation_code,
                    }
                    interation_result = await checkValid_instance.execute(
                        current_instance_id, interation_parameters
                    )
                    interation_response, interation_reward, interation_metrics = interation_result
                    interation_response_str = str(interation_response)
                    idx = parameter_space_dict.get("idx", 0)
                    space_key = f"space_{idx}"
                    # 收集仿真的原始数据
                    if space_key not in simulation_raw_data:
                        simulation_raw_data[space_key] = {
                            "parameter_space": parameter_space_dict,
                            "parameter_relation_code": parameter_relation_code,
                            "simulation_data": [],
                        }
                    if interation_metrics and "simulation_raw_data" in interation_metrics:
                        simulation_data = interation_metrics["simulation_raw_data"]
                        if isinstance(simulation_data, list):
                            simulation_raw_data[space_key]["simulation_data"].extend(simulation_data)
                        elif simulation_data is not None:
                            simulation_raw_data[space_key]["simulation_data"].append(simulation_data)
                    if isinstance(interation_response_str, str):
                        try:
                            interation_result_json = json.loads(interation_response_str)
                            if isinstance(interation_result_json, list):
                                for item in interation_result_json:
                                    if "comment" in item:
                                        del item["comment"]
                                    if "idx" not in item:
                                        item["idx"] = idx
                                all_interation_results.extend(interation_result_json)
                            elif isinstance(interation_result_json, dict):
                                if "comment" in interation_result_json:
                                    del interation_result_json["comment"]
                                if "idx" not in interation_result_json:
                                    interation_result_json["idx"] = idx
                                all_interation_results.append(interation_result_json)
                            else:
                                all_interation_results.append(
                                    {"idx": idx, "result": interation_response_str}
                                )
                        except Exception:
                            all_interation_results.append({"idx": idx, "result": interation_response_str})
                    elif isinstance(interation_response_str, list):
                        for item in interation_response_str:
                            if isinstance(item, dict):
                                if "comment" in item:
                                    del item["comment"]
                                if "idx" not in item:
                                    item["idx"] = idx
                                all_interation_results.append(item)
                            else:
                                all_interation_results.append({"idx": idx, "result": str(item)})
                    else:
                        all_interation_results.append({"idx": idx, "result": str(interation_response_str)})
                except Exception as e:
                    idx = parameter_space_dict.get("idx", 0)
                    # ✅ 修复：interation_name 未定义 -> 用 tool_name
                    error_msg = f"Error calling {tool_name} for space idx {idx}: {str(e)}"
                    all_interation_results.append({"idx": idx, "result": error_msg})
            # 如果没有任何结果，创建一个默认结果
            if len(all_interation_results) == 0:
                all_interation_results = [{"idx": 0, "result": "No spaces to validate"}]
            check_valid_content = (
                f"<CheckValid>{json.dumps(all_interation_results, ensure_ascii=False)}</CheckValid>"
            )
            additional_data = {"simulation_raw_data": simulation_raw_data}
            return False, check_valid_content, 0.0, additional_data
        except Exception as e:
            # ✅ 修复：interation_name 未定义 -> 用 tool_name
            import traceback
            traceback.print_exc()
            error_msg = f"Error calling {tool_name}: {str(e)}"
            idx = 0
            try:
                # 尝试从parameter_space_list中获取idx
                if isinstance(parameter_space_list, list) and len(parameter_space_list) > 0:
                    idx = parameter_space_list[0].get("idx", 0)
                elif isinstance(parameter_space_list, dict):
                    idx = parameter_space_list.get("idx", 0)
            except Exception:
                pass
            check_valid_content = (
                f'<CheckValid>[{{"idx": {idx}, "result": "{error_msg}"}}]</CheckValid>'
            )
            return False, check_valid_content, 0.0, {"simulation_raw_data": {}}
    async def calculate_score(self, instance_id: str, **kwargs) -> float:
        return super().calculate_score(instance_id, **kwargs)
    async def finalize_interaction(self, instance_id: str, **kwargs) -> bool:
        # 清理状态
        if instance_id in self._instance_state:
            # 释放工具实例
            state = self._instance_state[instance_id]
            context_instance_id_dict = state.get("context_instance_id_dict", {})
            interaction_instances = state.get("interaction_instances", {})
            for interation_name, interation_instance_id in context_instance_id_dict.items():
                if interation_instance_id and interation_name in interaction_instances:
                    interation_instance = interaction_instances[interation_name]["instance"]
                    try:
                        await interation_instance.release(interation_instance_id)
                    except Exception:
                        pass
            del self._instance_state[instance_id]
        return await super().finalize_interaction(instance_id, **kwargs)
