from __future__ import annotations

from typing import Any, Optional, Dict, List, Tuple
import json
import re
import yaml

from internbootcamp.utils.load_tool_from_config import load_tool_from_config
from internbootcamp.src.base_interaction import BaseInteraction


def _load_tools_from_yaml(yaml_path: str) -> Dict[str, Dict[str, Any]]:
    """Load tools from yaml and return {tool_name: {"instance": tool_instance, "schema": schema}}."""
