            func_name, schema, tool_instance = load_tool_from_config(tool_cfg)
            tool_instances[func_name] = {"instance": tool_instance, "schema": schema}
        except Exception as e:
            raise RuntimeError(
                f"Failed to load tool from config. func_name={func_name}, tool_cfg={tool_cfg}, err={e}"
            ) from e

    if not tool_instances:
        raise RuntimeError(f"No tools loaded from yaml: {yaml_path}")
    return tool_instances


class ACSInteraction(BaseInteraction):
    """
    ACSStage1 interaction:
    - Parse <ParameterSpace> and <ParameterRelationCode> from assistant output.
    - Call tool `checkValid` to validate.
    - Return <CheckValid>[{idx,result},...]</CheckValid>
    Compatible with multiple identity layouts:
      1) identity = {"checkValid": {...unfixed_parameters...}}
      2) identity = {"check": {...unfixed_parameters...}}
      3) identity = {...unfixed_parameters...}  (flat)
    """

    def __init__(self, config: dict[str, Any]):
        self.tool_instances = _load_tools_from_yaml(config["yaml_tool_path"])
        print("[ACSInteraction] Loaded tools:", list(self.tool_instances.keys()), flush=True)

        if "checkValid" not in self.tool_instances:
            raise RuntimeError(
                f"Tool 'checkValid' not found after loading. Available={list(self.tool_instances.keys())}"
            )

        super().__init__(config)

    async def start_interaction(
        self,
        instance_id: Optional[str] = None,
        identity: dict[str, Any] = None,
        **kwargs,
    ) -> str:
        return await super().start_interaction(instance_id, identity, **kwargs)

    # ---------------- parsing helpers ----------------

    def _extract_tag_content(self, content: str, tag: str) -> Optional[str]:
        """Extract the last complete <tag>...</tag> block (search from end)."""
        start_tag = f"<{tag}>"
        end_tag = f"</{tag}>"
        last_start_pos = content.rfind(start_tag)
        if last_start_pos == -1:
            return None
        search_start = last_start_pos + len(start_tag)
        end_pos = content.find(end_tag, search_start)
        if end_pos == -1:
            return None
        return content[search_start:end_pos].strip()

    def _clean_json_string(self, json_str: str) -> str:
        """
        Remove //, #, /* */ comments; fix trailing commas; convert single quotes to double quotes
        (only outside string context).
        """
        if not json_str:
            return json_str

        lines = json_str.split("\n")
        cleaned_lines: List[str] = []
        in_multiline_comment = False

        for line in lines:
            result_line: List[str] = []
            i = 0
            in_string = False
            escape_next = False
            string_char: Optional[str] = None

            while i < len(line):
                ch = line[i]

                if escape_next:
                    result_line.append(ch)
                    escape_next = False
                    i += 1
                    continue

                if ch == "\\":
                    result_line.append(ch)
                    escape_next = True
                    i += 1
                    continue

                # string start/end
                if (ch == '"' or ch == "'") and not escape_next:
                    if not in_string:
                        in_string = True
                        string_char = ch
                        result_line.append('"')  # normalize to JSON double quote
                    elif ch == string_char:
                        in_string = False
                        string_char = None
                        result_line.append('"')
                    else:
                        # different quote inside string
                        if string_char == "'" and ch == '"':
                            result_line.append('\\"')
                        else:
                            result_line.append(ch)
                    i += 1
                    continue

                if not in_string:
                    # multiline comment
                    if in_multiline_comment:
                        if i < len(line) - 1 and line[i : i + 2] == "*/":
                            in_multiline_comment = False
                            i += 2
                            continue
                        i += 1
                        continue

                    # // comment
                    if i < len(line) - 1 and line[i : i + 2] == "//":
                        break
                    # # comment
                    if ch == "#":
                        break
                    # start /* */
                    if i < len(line) - 1 and line[i : i + 2] == "/*":
                        in_multiline_comment = True
                        i += 2
                        continue

                result_line.append(ch)
                i += 1

            cleaned = "".join(result_line).rstrip()
            if cleaned:
                cleaned_lines.append(cleaned)

        result = "\n".join(cleaned_lines)
        # remove trailing commas before } or ]
        result = re.sub(r",(\s*[}\]])", r"\1", result)
        return result

    def _extract_parameter_space(
        self, content: str, debug: bool = False
    ) -> Tuple[Optional[List[Dict[str, Any]]], Optional[str]]:
        space_str = self._extract_tag_content(content, "ParameterSpace")
        if not space_str:
            return None, None
        try:
            cleaned = self._clean_json_string(space_str)
            obj = json.loads(cleaned)
            # allow dict or list; normalize later
            if isinstance(obj, dict):
                return [obj], None
            if isinstance(obj, list):
                return obj, None
            return None, f"ParameterSpace must be dict/list, got {type(obj).__name__}"
        except Exception as e:
            msg = f"ParameterSpace JSON提取失败: {e}"
            if debug:
                raise
            return None, msg

    def _extract_parameter_relation_code(
        self, content: str, debug: bool = False
    ) -> Tuple[Optional[str], Optional[str]]:
        code_str = self._extract_tag_content(content, "ParameterRelationCode")
        if not code_str:
            return None, "ParameterRelationCode标签未找到或为空"
        return code_str, None

    # ---------------- identity compatibility ----------------

    def _pick_identity_for_tool(
        self, interaction_instance: Dict[str, Any], tool_name: str
    ) -> Any:
        """
        Compatible identity selection:
          - identity[tool_name] (preferred if exists)
          - identity["check"]
          - identity (flat)
        """
        ident = interaction_instance.get("identity")
        if ident is None:
            return {}

        if isinstance(ident, dict):
            if tool_name in ident and isinstance(ident[tool_name], dict):
                return ident[tool_name]
            if "check" in ident and isinstance(ident["check"], dict):
                return ident["check"]
            return ident

        # if identity is not dict (rare), pass through
        return ident

    # ---------------- main ----------------

    async def generate_response(
        self, instance_id: str, messages: list[dict[str, Any]], **kwargs
    ) -> tuple[bool, str, float, dict[str, Any]]:

        interaction_instance = self._instance_dict[instance_id]

        # last assistant content
        content = ""
        for i in range(len(messages) - 1, -1, -1):
            m = messages[i]
            if m.get("role") == "assistant":
                content = m.get("content", "") or ""
                break

        # stop on <END>/<End>/<end>
        if re.search(r"<[Ee][Nn][Dd]>", content):
            return True, "", 0.0, {"simulation_raw_data": {}}

        if not interaction_instance:
            return False, "No interations available", 0.0, {"simulation_raw_data": {}}

        tool_name = "checkValid"

        try:
            spaces_to_check, space_error = self._extract_parameter_space(content)
            parameter_relation_code, relation_error = self._extract_parameter_relation_code(content)

            # format error -> return as CheckValid result (do not crash evaluation)
            if space_error is not None:
                error_result = [{"idx": 0, "result": f"ParameterSpace解析失败: {space_error}"}]
                return (
                    False,
                    f"<CheckValid>{json.dumps(error_result, ensure_ascii=False)}</CheckValid>",
                    0.0,
                    {"simulation_raw_data": {}},
                )
            if relation_error is not None:
                error_result = [{"idx": 0, "result": f"ParameterRelationCode解析失败: {relation_error}"}]
                return (
                    False,
                    f"<CheckValid>{json.dumps(error_result, ensure_ascii=False)}</CheckValid>",
                    0.0,
                    {"simulation_raw_data": {}},
                )

            if spaces_to_check is None or parameter_relation_code is None:
                return True, "", 0.0, {"simulation_raw_data": {}}

            if len(spaces_to_check) == 0:
                return True, "", 0.0, {"simulation_raw_data": {}}

            # tool instance
            if tool_name not in self.tool_instances:
                raise RuntimeError(
                    f"Tool '{tool_name}' not registered. available={list(self.tool_instances.keys())}"
                )
            check_valid_instance = self.tool_instances[tool_name]["instance"]

            # identity for tool (compatible)
            ident_for_tool = self._pick_identity_for_tool(interaction_instance, tool_name)

            # optional guard: make error explicit (instead of later KeyError in tool)
            if isinstance(ident_for_tool, dict) and "unfixed_parameters" not in ident_for_tool:
                raise RuntimeError(
                    f"identity for {tool_name} missing 'unfixed_parameters'. keys={list(ident_for_tool.keys())}"
                )

            create_kwargs = {"identity": ident_for_tool}
            create_result = await check_valid_instance.create(instance_id, **create_kwargs)

            if isinstance(create_result, tuple):
                current_instance_id, _create_resp = create_result
            else:
                current_instance_id = create_result

            all_results: List[Dict[str, Any]] = []
            simulation_raw_data: Dict[str, Any] = {}

            for parameter_space_dict in spaces_to_check:
                idx = 0
                if isinstance(parameter_space_dict, dict):
                    idx = parameter_space_dict.get("idx", 0)

                try:
                    tool_params = {
                        "ParameterSpace": parameter_space_dict,
                        "ParameterRelationCode": parameter_relation_code,
                    }
                    tool_response, tool_reward, tool_metrics = await check_valid_instance.execute(
                        current_instance_id, tool_params
                    )
                    resp_str = str(tool_response)

                    space_key = f"space_{idx}"
                    simulation_raw_data.setdefault(
                        space_key,
                        {
                            "parameter_space": parameter_space_dict,
                            "parameter_relation_code": parameter_relation_code,
                            "simulation_data": [],
                        },
                    )
                    if tool_metrics and "simulation_raw_data" in tool_metrics:
                        sim = tool_metrics["simulation_raw_data"]
                        if isinstance(sim, list):
                            simulation_raw_data[space_key]["simulation_data"].extend(sim)
                        elif sim is not None:
                            simulation_raw_data[space_key]["simulation_data"].append(sim)

                    # normalize tool response -> list[dict]
                    try:
                        parsed = json.loads(resp_str)
                        if isinstance(parsed, list):
                            for it in parsed:
                                if isinstance(it, dict):
                                    it.pop("comment", None)
                                    it.setdefault("idx", idx)
                                    all_results.append(it)
                                else:
                                    all_results.append({"idx": idx, "result": str(it)})
                        elif isinstance(parsed, dict):
                            parsed.pop("comment", None)
                            parsed.setdefault("idx", idx)
                            all_results.append(parsed)
                        else:
                            all_results.append({"idx": idx, "result": resp_str})
                    except Exception:
                        all_results.append({"idx": idx, "result": resp_str})

                except Exception as e:
                    all_results.append({"idx": idx, "result": f"Error calling {tool_name} for space idx {idx}: {e}"})

            if not all_results:
                all_results = [{"idx": 0, "result": "No spaces to validate"}]

            return (
                False,
                f"<CheckValid>{json.dumps(all_results, ensure_ascii=False)}</CheckValid>",
                0.0,
                {"simulation_raw_data": simulation_raw_data},
            )

        except Exception as e:
            # keep evaluation going; return error as tool output
            err = f"Error calling {tool_name}: {e}"
            return (
                False,
                f'<CheckValid>[{{"idx": 0, "result": "{err}"}}]</CheckValid>',
                0.0,
                {"simulation_raw_data": {}},
            )

    async def calculate_score(self, instance_id: str, **kwargs) -> float:
        return await super().calculate_score(instance_id, **kwargs)

    async def finalize_interaction(self, instance_id: str, **kwargs) -> bool:
        # release tool instances if BaseInteraction stored them
        if instance_id in self._instance_state:
            state = self._instance_state[instance_id]
            context_instance_id_dict = state.get("context_instance_id_dict", {})
            interaction_instances = state.get("interaction_instances", {})
            for name, iid in context_instance_id_dict.items():
                if iid and name in interaction_instances:
                    inst = interaction_instances[name]["instance"]
                    try:
                        await inst.release(iid)
                    except Exception:
                        pass
            del self._instance_state[instance_id]
        return await super().finalize_interaction(instance_id, **kwargs)
