        1) interaction_instance["identity"]
        2) interaction_instance["interaction_kwargs"]["identity"]
        3) interaction_instance["extra_info"]["interaction_kwargs"]["identity"]
        4) interaction_instance["template_input"]["extra_info"]["interaction_kwargs"]["identity"]
        5) kwargs["identity"] / kwargs["interaction_kwargs"]["identity"]  (some frameworks pass via call kwargs)
      And accept ANY of these shapes:
        A) {"checkValid": {...}}   (preferred)
        B) {"check": {...}}        (legacy)
        C) {...}                   (flat; contains unfixed_parameters)
    """
    TOOL_NAME = "checkValid"
    LEGACY_IDENTITY_KEYS = ("checkValid", "check", "CheckValid", "check_valid")
