    # ---------------- parsing helpers ----------------
    def _extract_tag_content(self, content: str, tag: str) -> Optional[str]:
        start_tag = f"<{tag}>"
        end_tag = f"</{tag}>"
        last_start_pos = content.rfind(start_tag)
        if last_start_pos == -1:
            return None
        search_start = last_start_pos + len(start_tag)
        end_pos = content.find(end_tag, search_start)
        if end_pos == -1:
            return None
        return content[search_start:end_pos].strip()
    def _clean_json_string(self, json_str: str) -> str:
        if not json_str:
